CREATE TYPE "JobStatus" AS ENUM ('queued','running','succeeded','partial','failed','cancelled');
CREATE TYPE "IntegrationStatus" AS ENUM ('healthy','stale','error','disconnected');
CREATE TABLE "Workspace" ("id" TEXT PRIMARY KEY,"name" TEXT NOT NULL,"locale" TEXT NOT NULL DEFAULT 'id-ID',"currency" TEXT NOT NULL DEFAULT 'IDR',"timezone" TEXT NOT NULL DEFAULT 'Asia/Jakarta',"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL);
CREATE TABLE "User" ("id" TEXT PRIMARY KEY,"workspaceId" TEXT NOT NULL REFERENCES "Workspace"("id") ON DELETE CASCADE,"email" TEXT NOT NULL UNIQUE,"passwordHash" TEXT NOT NULL,"name" TEXT NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL);
CREATE TABLE "BackgroundJob" ("id" TEXT PRIMARY KEY,"workspaceId" TEXT NOT NULL REFERENCES "Workspace"("id") ON DELETE CASCADE,"type" TEXT NOT NULL,"status" "JobStatus" NOT NULL DEFAULT 'queued',"idempotencyKey" TEXT NOT NULL,"attempts" INTEGER NOT NULL DEFAULT 0,"payload" JSONB,"result" JSONB,"errorCode" TEXT,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"startedAt" TIMESTAMP(3),"finishedAt" TIMESTAMP(3));
CREATE UNIQUE INDEX "BackgroundJob_workspaceId_idempotencyKey_key" ON "BackgroundJob"("workspaceId","idempotencyKey"); CREATE INDEX "BackgroundJob_status_createdAt_idx" ON "BackgroundJob"("status","createdAt");
CREATE TABLE "AuditLog" ("id" TEXT PRIMARY KEY,"workspaceId" TEXT NOT NULL REFERENCES "Workspace"("id") ON DELETE CASCADE,"actorId" TEXT,"action" TEXT NOT NULL,"entityType" TEXT NOT NULL,"entityId" TEXT,"metadata" JSONB,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP); CREATE INDEX "AuditLog_workspaceId_createdAt_idx" ON "AuditLog"("workspaceId","createdAt");
CREATE TABLE "SourceIntegration" ("id" TEXT PRIMARY KEY,"workspaceId" TEXT NOT NULL REFERENCES "Workspace"("id") ON DELETE CASCADE,"source" TEXT NOT NULL,"status" "IntegrationStatus" NOT NULL DEFAULT 'disconnected',"lastSyncedAt" TIMESTAMP(3),"lastErrorCode" TEXT,"freshnessHours" INTEGER NOT NULL DEFAULT 24,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL); CREATE UNIQUE INDEX "SourceIntegration_workspaceId_source_key" ON "SourceIntegration"("workspaceId","source");
